std::string g_report_file_name = "";
long g_total = 0;
double g_e2e_mean = 0.0;
double g_dpu_mean = 0.0;
bool g_stop = false;
std::atomic<int> _counter(0);
long act_time = 30000000;

class ImageListTIFF {
  public:
   explicit ImageListTIFF(const std::string &filename, bool lazy_load_image);
   ImageListTIFF(const ImageListTIFF &) = delete;
   ImageListTIFF &operator=(const ImageListTIFF &other) = delete;
   virtual ~ImageListTIFF();

  public:
   const cv::Mat operator[](long i) const;

   std::string to_string();
   void resize_images(int w, int h);

   bool empty() const { return list_.empty(); }
   size_t size() const { return list_.size(); }
   std::string getName(size_t i) const;

  public:
   struct Image {
     std::string name;
     cv::Mat mat;
   };

  private:
   std::vector<Image> list_;
   bool lazy_load_image_;
 };

 static std::vector<ImageListTIFF::Image> get_list(const std::string &filename,
                                               bool lazy_load_image) {
   std::ifstream fs(filename.c_str());
   std::string line;
   auto ret = std::vector<ImageListTIFF::Image>{};
   while (getline(fs, line)) {
     if (!lazy_load_image) {
       auto image = cv::imread(line, cv::IMREAD_UNCHANGED);
       if (image.empty()) {
         LOG(WARNING) << "cannot read image: " << line;
       } else {
         ret.emplace_back(ImageListTIFF::Image{line, image});
       }
     } else {
       ret.emplace_back(ImageListTIFF::Image{line, cv::Mat{}});
     }
   }
   fs.close();
   return ret;
 }

 inline ImageListTIFF::ImageListTIFF(const std::string &filename, bool lazy_load_image)
     : list_{get_list(filename, lazy_load_image)},
       lazy_load_image_{lazy_load_image} {}

 inline ImageListTIFF::~ImageListTIFF() {}

 inline std::string ImageListTIFF::to_string() {
   std::ostringstream str;
   int c = 0;
   for (const auto &image : list_) {
     if (c++ != 0) {
       str << ",";
     }
     str << image.name << image.mat.size();
   }
   return str.str();
 }

 inline const cv::Mat ImageListTIFF::operator[](long i) const {
   const auto &name = list_[i % list_.size()].name;
   const auto &mat = list_[i % list_.size()].mat;
   if (!lazy_load_image_) {
     return mat;
   }
   return cv::imread(name, cv::IMREAD_UNCHANGED);
 }

 inline std::string ImageListTIFF::getName(size_t i) const {
   const auto &name = list_[i % list_.size()].name;
   return name;
 }

 inline void ImageListTIFF::resize_images(int w, int h) {
   CHECK(!lazy_load_image_) << "only for eager load mode";
   for (auto &image : list_) {
     auto old = cv::Mat(std::move(image.mat));
     cv::resize(old, image.mat, cv::Size{w, h});
   }
 }


template <typename T>
inline BenchMarkResult thread_main_for_performance(const ImageListTIFF* image_list,
                                                   std::unique_ptr<T>&& model) {
  std::unique_lock<std::mutex> lock_t(g_mtx);
  lock_t.unlock();
  long ret = 0;
  StatSamples e2e_stat_samples(10000);
  StatSamples dpu_stat_samples(10000);
  while (!g_stop) {
    vitis::ai::TimeMeasure::getThreadLocalForDpu().reset();
    auto start = std::chrono::steady_clock::now();
    auto batch = model->get_input_batch();
    std::vector<cv::Mat> imgs;
    imgs.reserve(batch);
    for (auto n = 0u; n < batch; n++) {
      imgs.push_back((*image_list)[ret++]);
    }
    model->run(imgs);
    auto end = std::chrono::steady_clock::now();
    auto end2endtime =
        int(std::chrono::duration_cast<std::chrono::microseconds>(end - start)
                .count());
    auto dputime = vitis::ai::TimeMeasure::getThreadLocalForDpu().get();

    e2e_stat_samples.addSample(end2endtime);
    dpu_stat_samples.addSample(dputime);
    _counter += batch;
  }
  return BenchMarkResult{ret, std::move(e2e_stat_samples),
                         std::move(dpu_stat_samples)};
}

static void signal_handler(int signal) { g_stop = true; }
static void usage() {
  std::cout << "usage: env dpbenchmark \n"
               " -l <log_file_name> \n"
               " -t <num_of_threads> \n"
               " -s <num_of_seconds> \n"
               " <image list file> \n"
            << std::endl;
}
inline void parse_opt(int argc, char* argv[]) {
  int opt = 0;

  while ((opt = getopt(argc, argv, "t:s:l:")) != -1) {
    switch (opt) {
      case 't':
        g_num_of_threads = std::stoi(optarg);
        break;
      case 's':
        g_num_of_seconds = std::stoi(optarg);
        break;
      case 'l':
        g_report_file_name = optarg;
        break;
      default:
        usage();
        exit(1);
    }
  }
  if (optind >= argc) {
    std::cerr << "Expected argument after options\n";
    exit(EXIT_FAILURE);
  }
  g_list_name = argv[argc - 1];
  return;
}

static void report(std::ostream* p_out) {
  std::ostream& out = *p_out;
  float sec = (float)act_time / 1000000.0;
  float fps = ((float)g_total) / sec;
  out << "FPS=" << fps << "\n";
  out << "E2E_MEAN=" << g_e2e_mean << "\n";
  if (g_dpu_mean>0.01) {
    out << "DPU_MEAN=" << g_dpu_mean << "\n";
  }
  out << std::flush;
  return;
}

static void report_for_mt(std::ostream* p_out) {
  std::ostream& out = *p_out;
  float sec = (float)act_time / 1000000.0;
  float fps = ((float)g_total) / sec;
  out << "FPS=" << fps << "\n";
  out << std::flush;
  return;
}
int total_step = 0;
